import{_ as e,o as t,c as a,O as n}from"./chunks/framework.d5623306.js";const f=JSON.parse('{"title":"Enseignement","description":"","frontmatter":{"prev":false,"next":false,"image":"niagara.jpg","caption":"Niagara, Canada, aout 2010"},"headers":[],"relativePath":"fr/teaching/index.md","filePath":"fr/teaching/index.md"}'),r={name:"fr/teaching/index.md"},s=n('<h1 id="enseignement" tabindex="-1">Enseignement <a class="header-anchor" href="#enseignement" aria-label="Permalink to &quot;Enseignement&quot;">​</a></h1><p>Je travaille actuellement comme <em>professeur de cours technique</em> à temps partiel à l&#39;<a href="https://www.itscm.be" target="_blank" rel="noreferrer">Institut Technique Supérieur Cardinal Mercier</a> (ITSCM) et comme <em>chargé de cours</em> à temps partiel à l&#39;<a href="https://www.ephec.be" target="_blank" rel="noreferrer">EPHEC</a> et à la <a href="https://www.condorcet.be" target="_blank" rel="noreferrer">Haute École Provinciale de Hainaut</a> (HEPH-Condorcet), où je donne principalement des cours dans le domaine des <strong>sciences informatique</strong>.</p><p>Dans le passé, j&#39;ai travaillé comme <em>chargé de cours</em> à temps plein à l&#39;<a href="https://www.ecam.be" target="_blank" rel="noreferrer">ECAM Brussels Engineering School</a> (ECAM) de 2014 à 2020 et comme <em>assistant</em> à temps plein à l&#39;<a href="https://www.uclouvain.be/fr" target="_blank" rel="noreferrer">Université catholique de Louvain</a> (UCLouvain) de 2007 à 2013. J&#39;ai principalement donné des cours magistraux, supervisé des séances de travaux pratiques et encadré des étudiant(e)s, pour des cours dans le domaine des sciences informatiques. J&#39;ai également supervisé plusieurs <strong>stages et travaux de fin d&#39;étude</strong> lorsque j&#39;occupais ces postes.</p><p>Enfin, je donne également des <strong>formations et conférences</strong> sur des sujets divers et variés, principalement en lien avec l&#39;informatique, la gestion de projets et la communication efficace. Je suis aussi impliqué dans différents <strong>projets pédagogiques</strong> qui incluent le développement de dispositifs pédagogiques dont le but est d&#39;améliorer le taux de réussite des étudiant(e)s, en particulier les primo-arrivants.</p>',4),i=[s];function o(c,l,d,p,u,m){return t(),a("div",null,i)}const _=e(r,[["render",o]]);export{f as __pageData,_ as default};
